#include<bits/stdc++.h>
using namespace std;
long long x[100010],y[100010];
const long long mod=998244353;
long long fastpow(long long x,long long y)
{
    long long ans=1;
    while(y)
    {
        if(y%2==1)
        {
            ans=ans*x%mod;
        }
        x=x*x%mod;
        y/=2;
    }
    return ans;
}
int main()
{
    long long n,k;
    scanf("%lld%lld",&n,&k);
    for(int i=1;i<=n;i++)
    {
        scanf("%lld%lld",&x[i],&y[i]);
    }
    long long ans=0;
    for(long long i=1;i<=n;i++)
    {
        long long res=y[i];
        for(long long j=1;j<=n;j++)if(i!=j)
        {
            res*=(k-x[j])*fastpow(x[i]-x[j],mod-2)%mod;
            res%=mod;
        }
        ans+=res;
        ans%=mod;
    }
    printf("%lld",(ans+mod)%mod);
    return 0;
}
